 540 |         const visualW = width * s.scale;
 541 |         const visualH = height * s.scale;
 542 | 
 543 |         // X Constraint
 544 |         if (visualW < vw) {
 545 |             s.x = (vw - visualW) / 2;
 546 |             v.x = 0;
 547 |         } else {
 548 |             if (s.x > 0) { s.x = 0; v.x = 0; }
 549 |             if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
 550 |         }
 551 | 
 552 |         // Y Constraint
 553 |         if (visualH < vh) {
 554 |             s.y = (vh - visualH) / 2;
 555 |             v.y = 0;
 556 |         } else {
 557 |             if (s.y > 0) { s.y = 0; v.y = 0; }
 558 |             if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; }
 559 |         }
 560 |     };
 561 | 
 562 |     // The Single Render Loop
 563 |     // Decouples input frequency from screen refresh rate for buttery smooth motion
 564 |     const loop = () => {
 565 |         // 1. Apply Physics if not dragging
 566 |         if (!input.current.isDragging) {
 567 |             const v = velocity.current;
 568 |             // Apply snap-stop: if velocity is low, kill it immediately
 569 |             if (Math.abs(v.x) < 0.5) v.x = 0;
 570 |             if (Math.abs(v.y) < 0.5) v.y = 0;
 571 | 
 572 |             if (v.x !== 0 || v.y !== 0) {
 573 |                 v.x *= CONFIG.friction;
 574 |                 v.y *= CONFIG.friction;
 575 |                 state.current.x += v.x;
 576 |                 state.current.y += v.y;
 577 |             }
 578 |         }
 579 | 
 580 |         // 2. Apply Constraints (Borders)
 581 |         applyConstraints();
 582 | 
 583 |         // 3. Render to DOM
 584 |         if (layerRef.current) {
 585 |             const { x, y, scale } = state.current;
 586 |             // Using transform3d for hardware acceleration
 587 |             layerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${scale})`;
 588 |         }
 589 | 
 590 |         // 4. Update UI (Slider & Pages)
 591 |         if (sliderRef.current && pageCountRef.current && contentDims.current.height > 0) {
 592 |             // Use Unscaled values for stability across Zoom levels
 593 |             const unscaledTotalH = contentDims.current.height;
 594 |             const unscaledY = Math.abs(state.current.y) / state.current.scale;
 595 |             const viewHeight = window.innerHeight / state.current.scale;
 596 |             
 597 |             // Slider Progress (0-100%)
 598 |             // We compare unscaled position against the maximum possible unscaled scroll
 599 |             const maxScroll = Math.max(1, unscaledTotalH - viewHeight);
 600 |             
 601 |             if (!input.current.isSliderDragging) {
 602 |                 const progress = (unscaledY / maxScroll) * 100;
 603 |                 sliderRef.current.value = Math.max(0, Math.min(100, progress));
 604 |             }
 605 | 
 606 |             // Page Count Logic (Standard Book Ratio 1.3)
 607 |             // This calculates pages based on content dimensions (like an ebook), not screen height.
 608 |             // It ensures the count is stable (doesn't change with zoom) and more accurate (higher count on mobile).
 609 |             const bookPageHeight = contentDims.current.width * 1.3;
 610 |             const totalPages = Math.max(1, Math.ceil(unscaledTotalH / bookPageHeight));
 611 |             
 612 |             // Calculate current page based on the top visible edge
 613 |             const currentPage = Math.min(totalPages, Math.max(1, Math.floor((unscaledY + (bookPageHeight * 0.3)) / bookPageHeight) + 1));
 614 |             
 615 |             pageCountRef.current.innerText = `${currentPage}/${totalPages}`;
 616 |         }
 617 | 
 618 |         // 5. Continue Loop
 619 |         requestRef.current = requestAnimationFrame(loop);
 620 |     };
