ops.content:
:root {
    --miron-teal: #42d7b8;
    --miron-dark: #080808;
    --text-muted: #808080;
}

.miron-inline-portal {
    width: 100%;
    height: 100%;
    background-color: var(--miron-dark);
    position: relative;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    border-top: 2px solid var(--miron-teal);
    border-bottom: 2px solid var(--miron-teal);
    box-shadow: inset 0 20px 50px rgba(0,0,0,0.8);
    font-family: 'Poppins', sans-serif;
}

.portal-header {
    padding: 1.2rem 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    z-index: 10;
}

.context-chip {
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.context-label {
    font-size: 0.65rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--miron-teal);
    font-weight: 600;
}

.context-text {
    font-family: 'Newsreader', serif;
    font-style: italic;
    color: var(--text-muted);
    font-size: 0.85rem;
    max-width: 85%;
    line-height: 1.4;
}

.portal-flow {
    flex: 1;
    overflow-y: auto;
    padding: 0 1.5rem;
    display: flex;
    flex-direction: column;
    gap: 1.2rem;
    margin-bottom: 1rem;
}

.bubble {
    padding: 0.8rem 1.1rem;
    border-radius: 16px;
    font-size: 0.9rem;
    line-height: 1.5;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.08);
    color: #e0e0e0;
    max-width: 90%;
}

.portal-input-dock {
    padding: 1rem 1.5rem;
    background: var(--miron-dark);
}

.input-glass {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    padding: 6px 10px;
    display: flex;
    align-items: center;
    gap: 8px;
}

.input-glass input {
    flex: 1;
    background: transparent;
    border: none;
    outline: none;
    color: white;
    font-size: 0.9rem;
}

.send-btn {
    width: 32px;
    height: 32px;
    background: var(--miron-teal);
    color: var(--miron-dark);
    border: none;
    border-radius: 8px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

import React, { useState } from 'react';
import ReactDOM from 'react-dom';
import './MironInlineChat.css';

const MironInlineChat = ({ container, contextText, onClose }) => {
    const [input, setInput] = useState('');

    const content = (
        <div className="miron-inline-portal">
            <header className="portal-header">
                <div className="context-chip">
                    <span className="context-label">Miron Insight</span>
                    <span className="context-text">"{contextText.substring(0, 120)}..."</span>
                </div>
                <button className="close-btn" onClick={onClose} style={{ background: 'none', border: 'none', color: '#666', fontSize: '1.2rem', cursor: 'pointer' }}>
                    <i className="fas fa-times"></i>
                </button>
            </header>

            <main className="portal-flow">
                <div className="bubble">
                    I'm analyzing this passage. How can I help you explore this concept further?
                </div>
            </main>

            <footer className="portal-input-dock">
                <div className="input-glass">
                    <input 
                        type="text" 
                        placeholder="Ask a follow-up..." 
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                    />
                    <button className="send-btn">
                        <i className="fas fa-arrow-up"></i>
                    </button>
                </div>
            </footer>
        </div>
    );

    return ReactDOM.createPortal(content, container);
};

export default MironInlineChat;

