const handleAskMiron = () => {
    if (!contextMenu || !iframeRef.current) return;

    const doc = iframeRef.current.contentDocument;
    const GAP_HEIGHT = 450;
    const splitThreshold = contextMenu.rect.y + contextMenu.rect.height;

    // 1. Shift elements in Iframe
    const spans = Array.from(doc.querySelectorAll('span'));
    spans.forEach(span => {
        const rect = span.getBoundingClientRect();
        if (rect.top > contextMenu.rect.y + 10) {
            const currentTransform = span.style.transform || '';
            if (!currentTransform.includes('translateY')) {
                span.style.transform = `${currentTransform} translateY(${GAP_HEIGHT}px)`;
                span.style.transition = 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)';
            }
        }
    });

    // 2. Expand virtual dimensions for physics engine
    contentDims.current.height += GAP_HEIGHT;
    layerRef.current.style.height = `${contentDims.current.height}px`;
    doc.body.style.height = `${contentDims.current.height}px`;

    // 3. Inject Portal Container
    const containerId = `miron-gap-${Date.now()}`;
    const gapDiv = doc.createElement('div');
    gapDiv.id = containerId;
    gapDiv.style.cssText = `
        position: absolute;
        top: ${splitThreshold}px;
        left: 0;
        width: 100%;
        height: ${GAP_HEIGHT}px;
        z-index: 1000;
        animation: fadeIn 0.5s ease;
    `;
    doc.body.appendChild(gapDiv);

    setInlineChat({
        container: gapDiv,
        textContext: contextMenu.text,
        gapHeight: GAP_HEIGHT
    });

    setContextMenu(null);
};

const closeInlineChat = () => {
    if (!inlineChat || !iframeRef.current) return;
    const doc = iframeRef.current.contentDocument;

    // Reverse shifts
    const spans = Array.from(doc.querySelectorAll('span'));
    spans.forEach(span => {
        span.style.transform = span.style.transform.replace(/translateY\(.*?\)/, '');
    });

    // Revert dimensions
    contentDims.current.height -= inlineChat.gapHeight;
    layerRef.current.style.height = `${contentDims.current.height}px`;
    doc.body.style.height = `${contentDims.current.height}px`;

    // Cleanup DOM
    if (inlineChat.container.parentNode) {
        inlineChat.container.parentNode.removeChild(inlineChat.container);
    }

    setInlineChat(null);
};

const handleMenuAction = (action) => {
    if (action === 'ask_miron') {
        handleAskMiron();
    } else if (action === 'copy') {
        navigator.clipboard.writeText(contextMenu.text);
        setContextMenu(null);
    } else {
        setContextMenu(null);
    }
};

{inlineChat && (
    <MironInlineChat 
        container={inlineChat.container} 
        contextText={inlineChat.textContext} 
        onClose={closeInlineChat} 
    />
)}

